#include <iostream>\n\nclass Point {\n public:\n  explicit Point(int64_t x, int64_t y) : x_(x), y_(y) {}\n\n  int64_t GetX() const { return x_; }\n\n  int64_t GetY() const { return y_; }\n\n  bool operator==(const Point& point) const {\n    return x_ == point.x_ && y_ == point.y_;\n  }\n\n private:\n  int64_t x_;\n  int64_t y_;\n};\n\nclass Vector {\n public:\n  explicit Vector(int64_t x, int64_t y) : x_(x), y_(y) {}\n\n  explicit Vector(const Point& start, const Point& end)\n      : x_(end.GetX() - start.GetX()), y_(end.GetY() - start.GetY()) {}\n\n  int64_t operator^(const Vector& vect) { return x_ * vect.y_ - y_ * vect.x_; }\n\n  int64_t operator*(const Vector& vect) { return x_ * vect.x_ + y_ * vect.y_; }\n\n private:\n  int64_t x_;\n  int64_t y_;\n};\n\nclass Segment {\n public:\n  explicit Segment(int64_t x1, int64_t y1, int64_t x2, int64_t y2)\n      : first_(x1, y1), second_(x2, y2) {}\n\n  bool ContainsPoint(const Point& point) const {\n    if (point == first_ || point == second_) {\n      return true;\n    }\n    return ((Vector(first_, second_) ^ Vector(first_, point)) == 0) &&\n           (Vector(point, first_) * Vector(point, second_) <= 0);\n  }\n\n  bool CrossSegment(const Segment& seg) {\n    const Point& p1 = first_;\n    const Point& p2 = second_;\n    const Point& m1 = seg.first_;\n    const Point& m2 = seg.second_;\n    if (seg.ContainsPoint(p1) || seg.ContainsPoint(p2) || ContainsPoint(m1) ||\n        ContainsPoint(m2)) {\n      return true;\n    }\n    // [ P1P2 , P1M2 ] * [ P1P2, P1M1 ] < 0. [ M1M2, M1P1 ] * [ M1M2, M1P2 ] < 0\n    return ((Vector(p1, p2) ^ Vector(p1, m2)) *\n                (Vector(p1, p2) ^ Vector(p1, m1)) <\n            0) &&\n           ((Vector(m1, m2) ^ Vector(m1, p1)) *\n                (Vector(m1, m2) ^ Vector(m1, p2)) <\n            0);\n  }\n\n private:\n  Point first_;\n  Point second_;\n};\n\nint main() {\n  int64_t x1;\n  int64_t y1;\n  int64_t x2;\n  int64_t y2;\n\n  std::cin >> x1 >> y1 >> x2 >> y2;\n  Segment first(x1, y1, x2, y2);\n\n  std::cin >> x1 >> y1 >> x2 >> y2;\n  Segment second(x1, y1, x2, y2);\n\n  if (first.CrossSegment(second)) {\n    std::cout << \"YES\" << std::endl;\n  } else {\n    std::cout << \"NO\" << std::endl;\n  }\n  return 0;\n}